// Generate state before redirecting to OAuth provider
export async function GET() {
  const state = randomBytes(16).toString("hex");
  // Store state in session
  const res = new Response(null, { status: 302 });
  res.headers.set("Set-Cookie", `oauth_state=${state}; HttpOnly; Secure; SameSite=Lax; Path=/; Max-Age=600`);
  res.headers.set("Location",
    `https://provider.com/oauth/authorize?client_id=...&state=${state}&redirect_uri=...`
